#include <iostream>
#include <vector>
#include <cassert>
#include "744.cpp"

int main() {
    vector<vector<int>> input = {{1,1,1},{1,1,1},{1,1,1}};
    vector<vector<int>> filter = {{1,1,1},{1,1,1},{1,1,1}};
    vector<vector<int>> output;
    applyFilter(input, filter, output);
    // Center pixel of input surrounded by 1s. Sum = 9.
    assert(output.size() == 1 && output[0].size() == 1);
    assert(output[0][0] == 9);

    vector<vector<int>> small(2, vector<int>(2));
    applyFilter(small, filter, output);
    assert(output.empty());

    return 0;
}
